solution:
async function dapatkanData() {
  try {
    const response = await fetch('https://jsonplaceholder.typicode.com/users/1');
    const users = await response.json();
    console.log(users);
  } catch (error) {
    console.error('Gagal mengambil data:', error.message);
  }
}

dapatkanData();
